1	// Server-side Trigger.dev task dispatcher.
2	//
3	// Wraps tasks.trigger() so callers don't need to handle the case where:
4	//   - TRIGGER_SECRET_KEY is not set (Trigger.dev not yet configured)
5	//   - The Trigger.dev API is unreachable
6	//   - Tasks are not yet deployed
7	//
8	// All failures are logged as warnings and swallowed — the underlying business
9	// operation (upload, message insert, etc.) must NOT fail because Trigger.dev
10	// is unavailable. The cron-based sweeps will pick up un-triggered work.
11	
12	export async function triggerTask(
13	  taskId: string,
14	  payload: Record<string, unknown>,
15	): Promise<boolean> {
16	  const secretKey = process.env.TRIGGER_SECRET_KEY;
17	  if (!secretKey) {
18	    console.warn(
19	      `[trigger] TRIGGER_SECRET_KEY not configured — skipping trigger for "${taskId}". ` +
20	        'Set it in Vercel env to enable real-time task dispatch. Cron sweeps will pick up the work.',
21	    );
22	    return false;
23	  }
24	
25	  try {
26	    // Dynamic import so this module works in environments where @trigger.dev/sdk
27	    // is installed but not configured (avoids TRIGGER_SECRET_KEY read at import time).
28	    const { tasks } = await import('@trigger.dev/sdk/v3');
29	    await tasks.trigger(taskId, payload);
30	    console.log(`[trigger] dispatched task "${taskId}"`, payload);
31	    return true;
32	  } catch (err) {
33	    // Non-fatal: the cron sweep will catch it.
34	    console.warn(`[trigger] could not dispatch task "${taskId}":`, err);
35	    return false;
36	  }
37	}
