38	function intFromForm(formData: FormData, key: string, fallback: number): number {
39	  const raw = String(formData.get(key) ?? '').trim();
40	  const parsed = Number.parseInt(raw, 10);
41	  if (!Number.isFinite(parsed)) return fallback;
42	  return Math.max(1, Math.min(10, parsed));
43	}
