45	function buildAutoRevisionNote(input: {
46	  beforeSummary: string;
47	  afterSummary: string;
48	  beforeClaimType: string;
49	  afterClaimType: string;
50	  beforeImpact: number;
51	  afterImpact: number;
52	  beforeConfidence: number;
53	  afterConfidence: number;
54	  beforeDomains: string[];
55	  afterDomains: string[];
56	}): string {
57	  const changes: string[] = [];
58	  if (input.beforeSummary !== input.afterSummary) {
59	    changes.push(`summary changed from "${input.beforeSummary}" to "${input.afterSummary}"`);
60	  }
61	  if (input.beforeClaimType !== input.afterClaimType) {
62	    changes.push(`claim type changed from ${input.beforeClaimType} to ${input.afterClaimType}`);
63	  }
64	  if (input.beforeImpact !== input.afterImpact) {
65	    changes.push(`impact changed from ${input.beforeImpact} to ${input.afterImpact}`);
66	  }
67	  if (input.beforeConfidence !== input.afterConfidence) {
68	    changes.push(`confidence changed from ${input.beforeConfidence} to ${input.afterConfidence}`);
69	  }
70	  const beforeDomains = input.beforeDomains.join(', ') || '(none)';
71	  const afterDomains = input.afterDomains.join(', ') || '(none)';
72	  if (beforeDomains !== afterDomains) {
73	    changes.push(`domains changed from ${beforeDomains} to ${afterDomains}`);
74	  }
75	  return changes.length > 0
76	    ? `Reviewer revised the AI claim: ${changes.join('; ')}.`
77	    : 'Reviewer resubmitted the claim without changing the reviewed fields.';
78	}
