80	async function recalculateClaimDomainIds(input: {
81	  summary: string;
82	  claimType: string;
83	  fallbackDomainIds: string[];
84	}): Promise<{ domainIds: string[]; method: 'retrieval_plan_heuristic' | 'fallback_original_domains' }> {
85	  const db = getDirectDb();
86	  const plan = buildRetrievalPlanFromQuery(`${input.claimType}\n${input.summary}`);
87	  const inferredDomainIds = plan.topDomainHints;
88	  if (inferredDomainIds.length === 0) {
89	    return { domainIds: input.fallbackDomainIds, method: 'fallback_original_domains' };
90	  }
91	
92	  const validDomains = await db
93	    .select({ id: knowledgeTopDomains.id })
94	    .from(knowledgeTopDomains)
95	    .where(inArray(knowledgeTopDomains.id, inferredDomainIds));
96	  const validDomainIds = inferredDomainIds.filter((id) =>
97	    validDomains.some((domain) => domain.id === id),
98	  );
99	
100	  return validDomainIds.length > 0
101	    ? { domainIds: validDomainIds, method: 'retrieval_plan_heuristic' }
102	    : { domainIds: input.fallbackDomainIds, method: 'fallback_original_domains' };
103	}
