105	async function canReviewClaim(employeeId: string, isAdmin: boolean, claimId: string): Promise<boolean> {
106	  if (isAdmin) return true;
107	  const db = getDirectDb();
108	  const result = await db.execute(sql`
109	    SELECT EXISTS (
110	      SELECT 1
111	      FROM gaps g
112	      WHERE g.gap_type = 'claim_review_question'
113	        AND g.target_employee_id = ${employeeId}::uuid
114	        AND g.status IN ('open', 'queued', 'asked')
115	        AND g.related_claim_ids ? ${claimId}
116	    ) AS allowed
117	  `);
118	  const row = [...result][0] as { allowed?: boolean } | undefined;
119	  return row?.allowed === true;
120	}
