14	function normalizeSourceText(text: string | null, quote: string | null): string {
15	  const trimmed = (text ?? '').trim();
16	  const trimmedQuote = (quote ?? '').trim();
17	  if (!trimmed && trimmedQuote) return trimmedQuote;
18	  if (!trimmed) return '';
19	  if (!trimmedQuote) return trimmed.slice(0, 12_000);
20	
21	  const quoteIndex = trimmed.indexOf(trimmedQuote);
22	  if (quoteIndex < 0) return trimmedQuote;
23	
24	  const start = Math.max(0, quoteIndex - 4_000);
25	  const end = Math.min(trimmed.length, quoteIndex + trimmedQuote.length + 4_000);
26	  return trimmed.slice(start, end);
27	}
