29	async function loadSourceForReviewEvent(reviewEventId: string) {
30	  const db = getDirectDb();
31	  const result = await db.execute(sql`
32	    SELECT
33	      cre.id AS review_event_id,
34	      cre.claim_id AS source_claim_id,
35	      cre.replacement_claim_id AS revised_claim_id,
36	      ce.source_type,
37	      COALESCE(ce.source_message_id, ce.source_document_chunk_id) AS source_id,
38	      ce.exact_quote,
39	      COALESCE(m.content, dc.raw_text, ce.exact_quote) AS source_text
40	    FROM claim_review_events cre
41	    JOIN LATERAL (
42	      SELECT *
43	      FROM (
44	        SELECT ce.*, 0 AS evidence_priority
45	        FROM claim_evidence ce
46	        WHERE ce.claim_id = cre.replacement_claim_id
47	        UNION ALL
48	        SELECT ce.*, 1 AS evidence_priority
49	        FROM claim_evidence ce
50	        WHERE ce.claim_id = cre.claim_id
51	      ) ranked_evidence
52	      ORDER BY evidence_priority, confidence DESC NULLS LAST, created_at ASC
53	      LIMIT 1
54	    ) ce ON true
55	    LEFT JOIN messages m ON m.id = ce.source_message_id
56	    LEFT JOIN document_chunks dc ON dc.id = ce.source_document_chunk_id
57	    WHERE cre.id = ${reviewEventId}::uuid
58	      AND cre.action = 'revise'
59	      AND cre.replacement_claim_id IS NOT NULL
60	    LIMIT 1
61	  `);
62	  const row = [...result][0] as
63	    | {
64	        review_event_id: string;
65	        source_claim_id: string;
66	        revised_claim_id: string;
67	        source_type: string;
68	        source_id: string | null;
69	        exact_quote: string | null;
70	        source_text: string | null;
71	      }
72	    | undefined;
73	  if (!row) throw new Error('Could not find source evidence for this revised claim.');
74	  const sourceExcerpt = normalizeSourceText(row.source_text, row.exact_quote);
75	  if (!sourceExcerpt) throw new Error('Could not find usable source evidence text for this revised claim.');
76	  return {
77	    ...row,
78	    source_excerpt: sourceExcerpt,
79	  };
80	}
