1	// Server-side Supabase clients for Next.js App Router (RSC, route handlers).
2	// Uses @supabase/ssr cookie storage (v0.10+ getAll/setAll shape).
3	//
4	// IMPORTANT: There are two clients here.
5	//   * `createAuthClient`         — uses the anon key + user cookies. RLS applies.
6	//   * `createServiceRoleClient`  — uses the service role key. Bypasses RLS.
7	//
8	// Browser/client code must never import this file.
9	
10	import { createServerClient, type CookieOptions } from '@supabase/ssr';
11	import { createClient } from '@supabase/supabase-js';
12	import WebSocket from 'ws';
13	
14	export type CookieAdapter = {
15	  getAll(): Array<{ name: string; value: string }>;
16	  setAll(
17	    cookies: Array<{ name: string; value: string; options?: CookieOptions }>,
18	  ): void;
19	};
20	
21	function requireEnv(name: string): string {
22	  const v = process.env[name];
23	  if (!v) throw new Error(`Missing required env var ${name}.`);
24	  return v;
25	}
26	
27	const WebSocketTransport = WebSocket as unknown as typeof globalThis.WebSocket;
28	
29	export function createAuthClient(cookies: CookieAdapter) {
30	  return createServerClient(
31	    requireEnv('NEXT_PUBLIC_SUPABASE_URL'),
32	    requireEnv('NEXT_PUBLIC_SUPABASE_ANON_KEY'),
33	    {
34	      cookies: {
35	        getAll: () => cookies.getAll(),
36	        setAll: (toSet) => cookies.setAll(toSet),
37	      },
38	    },
39	  );
40	}
41	
42	/**
43	 * Service-role Supabase client (server-only). Bypasses RLS. Use for:
44	 *   - first-login linking (writes to employees)
45	 *   - Oracle route handlers that need to fetch context across employees/channels
46	 *
47	 * NEVER ship this client to the browser.
48	 */
49	export function createServiceRoleClient() {
50	  return createClient(
51	    requireEnv('NEXT_PUBLIC_SUPABASE_URL'),
52	    requireEnv('SUPABASE_SERVICE_ROLE_KEY'),
53	    {
54	      auth: {
55	        persistSession: false,
56	        autoRefreshToken: false,
57	      },
58	      realtime: {
59	        transport: WebSocketTransport,
60	      },
61	    },
62	  );
63	}
64	
65	/**
66	 * Helper used by the /auth/callback route: given the current cookie store,
67	 * return { user, employee } if the employee is approved, else { error }.
68	 */
69	export async function resolveCurrentSession(cookies: CookieAdapter) {
70	  const supabase = createAuthClient(cookies);
71	  const { data, error } = await supabase.auth.getUser();
72	  if (error || !data.user) {
73	    return { ok: false as const, reason: 'no_session' as const };
74	  }
75	  return { ok: true as const, user: data.user };
76	}
77	
78	/**
79	 * Helper to convert the Supabase user object's app_metadata into our
80	 * AuthProvider enum value. For the magic-link dev stub this returns
81	 * 'magic_link_dev'.
82	 */
83	export function resolveAuthProvider(user: { app_metadata?: { provider?: string } }) {
84	  const p = user.app_metadata?.provider;
85	  if (p === 'google') return 'google' as const;
86	  if (p === 'azure' || p === 'microsoft') return 'microsoft' as const;
87	  if (p === 'authentik' || p === 'oidc') return 'authentik' as const;
88	  // Email magic-link is the Phase 1 stub.
89	  return 'magic_link_dev' as const;
90	}
