1	'use server';
2	
3	import { revalidatePath } from 'next/cache';
4	import { and, eq, inArray, sql } from 'drizzle-orm';
5	import { z } from 'zod';
6	import {
7	  departments,
8	  employeeDepartments,
9	  employees,
10	} from '@oracle/db/schema';
11	import { getDirectDb } from '@oracle/db/client';
12	import { DEPARTMENTS, type Department } from '@oracle/shared';
13	import { requireAdmin } from '@/lib/auth-guard';
14	
15	const departmentIdEnum = z.enum(
16	  DEPARTMENTS as unknown as [Department, ...Department[]],
17	);
18	
19	// ---------------------------------------------------------------------------
20	// updateDepartment — label / description / head.
21	// ---------------------------------------------------------------------------
22	
23	const UpdateDepartmentSchema = z.object({
24	  id: departmentIdEnum,
25	  displayLabel: z.string().min(1).max(120),
26	  // Empty string in the form means "clear it".
27	  description: z.string().max(2000),
28	  // 'none' (or '') means clear; otherwise a uuid that MUST already be a
29	  // member of this department (enforced below).
30	  headEmployeeId: z.string(),
31	});
32	
33	export type UpdateDepartmentState = {
34	  ok: boolean;
35	  error?: string;
36	};
37	
38	export async function updateDepartment(
39	  _prev: UpdateDepartmentState,
40	  formData: FormData,
41	): Promise<UpdateDepartmentState> {
42	  await requireAdmin();
43	  const db = getDirectDb();
44	
45	  const parsed = UpdateDepartmentSchema.safeParse({
46	    id: formData.get('id'),
47	    displayLabel: formData.get('displayLabel'),
48	    description: formData.get('description') ?? '',
49	    headEmployeeId: formData.get('headEmployeeId') ?? '',
50	  });
51	  if (!parsed.success) {
52	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
53	  }
54	
55	  const { id, displayLabel, description, headEmployeeId } = parsed.data;
56	  const headId = headEmployeeId && headEmployeeId !== 'none' ? headEmployeeId : null;
57	
58	  // Enforce: a non-null head must be a current member of this department.
59	  if (headId) {
60	    const isMember = await db
61	      .select({ employeeId: employeeDepartments.employeeId })
62	      .from(employeeDepartments)
63	      .where(
64	        and(
65	          eq(employeeDepartments.departmentId, id),
66	          eq(employeeDepartments.employeeId, headId),
67	        ),
68	      )
69	      .limit(1);
70	    if (isMember.length === 0) {
71	      return {
72	        ok: false,
73	        error: 'Selected head is not a member of this department. Add them as a member first.',
74	      };
75	    }
76	  }
77	
78	  try {
79	    await db
80	      .update(departments)
81	      .set({
82	        displayLabel,
83	        description: description.trim() === '' ? null : description,
84	        headEmployeeId: headId,
85	      })
86	      .where(eq(departments.id, id));
87	  } catch (err) {
88	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
89	  }
90	
91	  revalidatePath('/admin/departments');
92	  revalidatePath('/admin/employees');
93	  return { ok: true };
94	}
95	
96	// ---------------------------------------------------------------------------
97	// addDepartmentMember — add one employee to this department.
98	//
99	// Writes the join row, then syncs the legacy employees.departments text[]
100	// to include the department's display label (retrieval-plan reads the text[]
101	// today). Idempotent on both sides.
102	// ---------------------------------------------------------------------------
103	
104	const MemberMutationSchema = z.object({
105	  departmentId: departmentIdEnum,
106	  employeeId: z.string().uuid(),
107	});
108	
109	export type MemberMutationState = {
110	  ok: boolean;
111	  error?: string;
112	};
113	
114	export async function addDepartmentMember(
115	  _prev: MemberMutationState,
116	  formData: FormData,
117	): Promise<MemberMutationState> {
118	  await requireAdmin();
119	  const db = getDirectDb();
120	
121	  const parsed = MemberMutationSchema.safeParse({
122	    departmentId: formData.get('departmentId'),
123	    employeeId: formData.get('employeeId'),
124	  });
125	  if (!parsed.success) {
126	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
127	  }
128	
129	  const { departmentId, employeeId } = parsed.data;
130	
131	  try {
132	    const [dept] = await db
133	      .select({ label: departments.displayLabel })
134	      .from(departments)
135	      .where(eq(departments.id, departmentId))
136	      .limit(1);
137	    if (!dept) return { ok: false, error: 'Department not found.' };
138	
139	    await db.transaction(async (tx) => {
140	      await tx
141	        .insert(employeeDepartments)
142	        .values({ employeeId, departmentId })
143	        .onConflictDoNothing();
144	
145	      // Append display label to legacy text[] if not already present.
146	      await tx
147	        .update(employees)
148	        .set({
149	          departments: sql`(
150	            SELECT array_agg(DISTINCT x)
151	            FROM unnest(${employees.departments} || ARRAY[${dept.label}]::text[]) AS x
152	          )`,
153	        })
154	        .where(eq(employees.id, employeeId));
155	    });
156	  } catch (err) {
157	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
158	  }
159	
160	  revalidatePath('/admin/departments');
161	  revalidatePath('/admin/employees');
162	  return { ok: true };
163	}
164	
165	// ---------------------------------------------------------------------------
166	// removeDepartmentMember — pull one employee off this department.
167	//
168	// Also clears `departments.head_employee_id` if the removed employee was the
169	// head (otherwise we'd have an inconsistent "head who isn't a member" state).
170	// ---------------------------------------------------------------------------
171	
172	export async function removeDepartmentMember(
173	  _prev: MemberMutationState,
174	  formData: FormData,
175	): Promise<MemberMutationState> {
176	  await requireAdmin();
177	  const db = getDirectDb();
178	
179	  const parsed = MemberMutationSchema.safeParse({
180	    departmentId: formData.get('departmentId'),
181	    employeeId: formData.get('employeeId'),
182	  });
183	  if (!parsed.success) {
184	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
185	  }
186	
187	  const { departmentId, employeeId } = parsed.data;
188	
189	  try {
190	    const [dept] = await db
191	      .select({ label: departments.displayLabel, headEmployeeId: departments.headEmployeeId })
192	      .from(departments)
193	      .where(eq(departments.id, departmentId))
194	      .limit(1);
195	    if (!dept) return { ok: false, error: 'Department not found.' };
196	
197	    await db.transaction(async (tx) => {
198	      await tx
199	        .delete(employeeDepartments)
200	        .where(
201	          and(
202	            eq(employeeDepartments.departmentId, departmentId),
203	            eq(employeeDepartments.employeeId, employeeId),
204	          ),
205	        );
206	
207	      // Remove display label from legacy text[].
208	      await tx
209	        .update(employees)
210	        .set({
211	          departments: sql`array_remove(${employees.departments}, ${dept.label})`,
212	        })
213	        .where(eq(employees.id, employeeId));
214	
215	      // Clear head if this employee was it.
216	      if (dept.headEmployeeId === employeeId) {
217	        await tx
218	          .update(departments)
219	          .set({ headEmployeeId: null })
220	          .where(eq(departments.id, departmentId));
221	      }
222	    });
223	  } catch (err) {
224	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
225	  }
226	
227	  revalidatePath('/admin/departments');
228	  revalidatePath('/admin/employees');
229	  return { ok: true };
230	}
