35	export async function addEmployee(
36	  _prev: AddEmployeeState,
37	  formData: FormData,
38	): Promise<AddEmployeeState> {
39	  await requireAdmin();
40	  const db = getDirectDb();
41	
42	  const parsed = AddEmployeeSchema.safeParse({
43	    name: formData.get('name'),
44	    email: formData.get('email'),
45	    role: formData.get('role'),
46	    departmentIds: formData.getAll('departmentIds'),
47	    isAdmin: formData.get('isAdmin') === 'true',
48	  });
49	  if (!parsed.success) {
50	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
51	  }
52	
53	  const { name, email, role, departmentIds, isAdmin } = parsed.data;
54	
55	  try {
56	    // Fetch display labels so the legacy text[] column carries human-readable
57	    // values (retrieval-plan.ts uses them as soft RRF hints — see the
58	    // comments on the employees.departments column in schema.ts).
59	    const labelRows = await db
60	      .select({ id: departments.id, label: departments.displayLabel })
61	      .from(departments)
62	      .where(inArray(departments.id, departmentIds));
63	    const labelById = new Map(labelRows.map((r) => [r.id, r.label]));
64	    const orderedLabels = departmentIds.map((id) => labelById.get(id) ?? id);
65	
66	    await db.transaction(async (tx) => {
67	      const [inserted] = await tx
68	        .insert(employees)
69	        .values({
70	          name,
71	          email,
72	          role,
73	          department: orderedLabels[0],
74	          departments: orderedLabels,
75	          isAdmin,
76	        })
77	        .onConflictDoNothing({ target: employees.email })
78	        .returning({ id: employees.id });
79	
80	      if (inserted) {
81	        await tx.insert(employeeDepartments).values(
82	          departmentIds.map((departmentId) => ({
83	            employeeId: inserted.id,
84	            departmentId,
85	          })),
86	        );
87	      }
88	    });
89	  } catch (err) {
90	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
91	  }
92	
93	  revalidatePath('/admin/employees');
94	  revalidatePath('/admin/departments');
95	  return { ok: true };
96	}
