168	// ---------------------------------------------------------------------------
169	// Disable / re-enable employee access.
170	// Soft-disable via employees.disabled_at so historical messages, claims,
171	// evidence, assignments, and audit records keep their employee references.
172	// ---------------------------------------------------------------------------
173	
174	const UpdateEmployeeAccessSchema = z.object({
175	  employeeId: z.string().uuid(),
176	  action: z.enum(['disable', 'enable']),
177	});
178	
179	export type UpdateEmployeeAccessState = {
180	  ok: boolean;
181	  error?: string;
182	};
183	
184	export async function updateEmployeeAccess(
185	  _prev: UpdateEmployeeAccessState,
186	  formData: FormData,
187	): Promise<UpdateEmployeeAccessState> {
188	  const me = await requireAdmin();
189	  const db = getDirectDb();
190	
191	  const parsed = UpdateEmployeeAccessSchema.safeParse({
192	    employeeId: formData.get('employeeId'),
193	    action: formData.get('action'),
194	  });
195	  if (!parsed.success) {
196	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
197	  }
198	
199	  const { employeeId, action } = parsed.data;
200	  if (action === 'disable' && employeeId === me.id) {
201	    return { ok: false, error: 'You cannot disable your own active admin account.' };
202	  }
203	
204	  try {
205	    const [target] = await db
206	      .select({
207	        id: employees.id,
208	        isAdmin: employees.isAdmin,
209	        disabledAt: employees.disabledAt,
210	      })
211	      .from(employees)
212	      .where(eq(employees.id, employeeId))
213	      .limit(1);
214	    if (!target) return { ok: false, error: 'Employee not found.' };
215	
216	    if (action === 'disable' && target.isAdmin && !target.disabledAt) {
217	      const adminCountResult = await db.execute(sql`
218	        SELECT count(*)::int AS active_admin_count
219	        FROM employees
220	        WHERE is_admin = true
221	          AND disabled_at IS NULL
222	          AND id <> ${employeeId}::uuid
223	      `);
224	      const activeAdminCount = Number(
225	        ([...adminCountResult][0] as { active_admin_count?: number } | undefined)
226	          ?.active_admin_count ?? 0,
227	      );
228	      if (activeAdminCount < 1) {
229	        return { ok: false, error: 'At least one active admin must remain.' };
230	      }
231	    }
232	
233	    await db
234	      .update(employees)
235	      .set({ disabledAt: action === 'disable' ? new Date() : null })
236	      .where(eq(employees.id, employeeId));
237	  } catch (err) {
238	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
239	  }
240	
241	  revalidatePath('/admin/employees');
242	  return { ok: true };
243	}
