296	// ---------------------------------------------------------------------------
297	// Invite a Microsoft 365 user as a new Oracle employee.
298	//
299	// Distinct from addEmployee: allows zero departments (admin assigns later)
300	// and triggers a Supabase admin invite email so the recipient knows they've
301	// been added. When they next sign in (via Microsoft SSO or magic link), the
302	// existing identity linker matches by email and merges them in.
303	// ---------------------------------------------------------------------------
304	
305	const InviteFromM365Schema = z.object({
306	  email: z.string().email().max(320),
307	  name: z.string().min(1).max(255),
308	  // Optional at invite time. The admin will fix it via the inline editor
309	  // once the row exists, OR pre-pick a couple here if they already know.
310	  departmentIds: z.array(departmentIdEnum).optional().default([]),
311	  // Optional Graph-supplied job title.
312	  jobTitle: z.string().max(255).optional().default(''),
313	});
314	
315	export type InviteFromM365State = {
316	  ok: boolean;
317	  error?: string;
318	  /** Set to true when the DB insert succeeded but the email send failed. */
319	  emailFailed?: boolean;
320	};
321	
322	export async function inviteFromM365(
323	  _prev: InviteFromM365State,
324	  formData: FormData,
325	): Promise<InviteFromM365State> {
326	  await requireAdmin();
327	  const db = getDirectDb();
328	
329	  const parsed = InviteFromM365Schema.safeParse({
330	    email: (formData.get('email') as string | null)?.toLowerCase().trim() ?? '',
331	    name: formData.get('name'),
332	    departmentIds: formData.getAll('departmentIds'),
333	    jobTitle: formData.get('jobTitle') ?? '',
334	  });
335	  if (!parsed.success) {
336	    return { ok: false, error: parsed.error.issues.map((i) => i.message).join('; ') };
337	  }
338	
339	  const { email, name, departmentIds, jobTitle } = parsed.data;
340	  const role = jobTitle.trim() || 'Employee';
341	
342	  // Department labels (only needed when at least one was picked).
343	  let orderedLabels: string[] = [];
344	  if (departmentIds.length > 0) {
345	    const labelRows = await db
346	      .select({ id: departments.id, label: departments.displayLabel })
347	      .from(departments)
348	      .where(inArray(departments.id, departmentIds));
349	    const labelById = new Map(labelRows.map((r) => [r.id, r.label]));
350	    orderedLabels = departmentIds.map((id) => labelById.get(id) ?? id);
351	  }
352	
353	  try {
354	    await db.transaction(async (tx) => {
355	      const [inserted] = await tx
356	        .insert(employees)
357	        .values({
358	          name,
359	          email,
360	          role,
361	          department: orderedLabels[0] ?? null,
362	          departments: orderedLabels,
363	          isAdmin: false,
364	        })
365	        .onConflictDoNothing({ target: employees.email })
366	        .returning({ id: employees.id });
367	
368	      if (inserted && departmentIds.length > 0) {
369	        await tx.insert(employeeDepartments).values(
370	          departmentIds.map((departmentId) => ({
371	            employeeId: inserted.id,
372	            departmentId,
373	          })),
374	        );
375	      }
376	    });
377	  } catch (err) {
378	    return { ok: false, error: err instanceof Error ? err.message : String(err) };
379	  }
380	
381	  // Send the magic-link invite via Supabase admin (routes through Brevo SMTP
382	  // configured at the Supabase project level). Failure here is non-fatal —
383	  // the employee row is already in place; the admin can resend manually or
384	  // the user can sign in via SSO with no email.
385	  try {
386	    const supabase = getServiceRoleSupabase();
387	    const { error } = await supabase.auth.admin.inviteUserByEmail(email, {
388	      data: { invited_via: 'm365_directory_pull', display_name: name },
389	    });
390	    if (error) {
391	      console.error('[inviteFromM365] supabase invite email failed', error);
392	      revalidatePath('/admin/employees');
393	      return { ok: true, emailFailed: true };
394	    }
395	  } catch (err) {
396	    console.error('[inviteFromM365] supabase invite threw', err);
397	    revalidatePath('/admin/employees');
398	    return { ok: true, emailFailed: true };
399	  }
400	
401	  revalidatePath('/admin/employees');
402	  return { ok: true };
403	}
