32	
33	export async function rejectTaxonomyProposal(proposalId: string, reason: string) {
34	  const me = await requireAdmin();
35	  const db = getDirectDb();
36	
37	  await db.transaction(async (tx) => {
38	    const [proposal] = await tx
39	      .select()
40	      .from(taxonomyProposals)
41	      .where(and(eq(taxonomyProposals.id, proposalId), eq(taxonomyProposals.status, 'pending')))
42	      .limit(1);
43	    if (!proposal) throw new Error('Proposal not found or already reviewed');
44	
45	    await tx
46	      .update(taxonomyProposals)
47	      .set({
48	        status: 'rejected',
49	        reviewedByEmployeeId: me.id,
50	        reviewedAt: new Date(),
51	      })
52	      .where(eq(taxonomyProposals.id, proposalId));
53	
54	    await tx.insert(taxonomyChangeLog).values({
55	      changeType: `reject_${proposal.proposalType}`,
56	      beforeState: { proposalId, proposalType: proposal.proposalType, payload: proposal.payload },
57	      afterState: null,
58	      reason,
59	      approvedByEmployeeId: me.id,
60	      proposalId,
61	    });
62	  });
63	
64	  revalidatePath('/admin/taxonomy/proposals');
65	  revalidatePath('/admin/taxonomy/change-log');
