68	/**
69	 * Approve a proposal. The mutation depends on the proposal type:
70	 *
71	 *   - create_top_domain → INSERT into knowledge_top_domains using the
72	 *     proposal payload (boundary rules included). This is the only
73	 *     mutation currently implemented inline; the reclassification path
74	 *     for merge_top_domains / split_top_domain / reassign_claims /
75	 *     create_sub_topic / merge_sub_topics / split_sub_topic / retire_sub_topic
76	 *     is scaffolded as a TODO — those need targeted reclassification of
77	 *     claim_top_domains / claim_sub_topics rows + optional Brain
78	 *     synthesis re-runs (the "transactional reclassification job"
79	 *     from R10.5 task 4 in the retrofit packet).
80	 *
81	 *   For the unimplemented branches, the proposal is marked approved
82	 *   (recording the reviewer) and the change log row is written, but
83	 *   the actual reclassification is queued as a TODO note. This
84	 *   preserves the audit trail without auto-mutating the taxonomy
85	 *   in ways the reclassifier isn't yet ready to handle.
86	 */
87	export async function approveTaxonomyProposal(proposalId: string, reviewNote: string | null) {
88	  const me = await requireAdmin();
89	  const db = getDirectDb();
90	
91	  await db.transaction(async (tx) => {
92	    const [proposal] = await tx
93	      .select()
94	      .from(taxonomyProposals)
95	      .where(and(eq(taxonomyProposals.id, proposalId), eq(taxonomyProposals.status, 'pending')))
96	      .limit(1);
97	    if (!proposal) throw new Error('Proposal not found or already reviewed');
98	
99	    // Mark approved first (the CHECK constraint enforces reviewer + timestamp).
100	    await tx
101	      .update(taxonomyProposals)
102	      .set({
103	        status: 'approved',
104	        reviewedByEmployeeId: me.id,
105	        reviewedAt: new Date(),
106	      })
107	      .where(eq(taxonomyProposals.id, proposalId));
108	
109	    // Apply the mutation per type.
110	    type Payload = Record<string, unknown> & {
111	      proposedId?: string;
112	      proposedName?: string;
113	      oneSentencePurpose?: string;
114	      proposalReason?: string;
115	      boundaryRules?: {
116	        belongsHere?: unknown[];
117	        doesNotBelongHere?: unknown[];
118	        commonEntityHints?: unknown[];
119	        defaultExcludedDocumentClasses?: string[];
120	        neighboringDomainIds?: string[];
121	      };
122	      suggestedRetrievalExclusions?: string[];
123	    };
124	    const payload = (proposal.payload ?? {}) as Payload;
125	
126	    let afterState: unknown = null;
127	    let queuedReclassification = false;
128	
129	    if (proposal.proposalType === 'create_top_domain') {
130	      const id = (payload.proposedId ?? '').trim();
131	      const name = (payload.proposedName ?? '').trim();
132	      if (!id || !name) {
133	        throw new Error('create_top_domain proposal is missing proposedId or proposedName');
134	      }
135	      // display_order: place at the end of the active list.
136	      const allDomains = await tx
137	        .select({ displayOrder: knowledgeTopDomains.displayOrder })
138	        .from(knowledgeTopDomains);
139	      const maxOrder = allDomains.reduce((m, r) => (r.displayOrder > m ? r.displayOrder : m), 0);
140	
141	      const [inserted] = await tx
142	        .insert(knowledgeTopDomains)
143	        .values({
144	          id,
145	          name,
146	          description: payload.oneSentencePurpose ?? '(approved from proposal)',
147	          belongsHere: (payload.boundaryRules?.belongsHere ?? []) as unknown[],
148	          doesNotBelongHere: (payload.boundaryRules?.doesNotBelongHere ?? []) as unknown[],
149	          commonEntityHints: (payload.boundaryRules?.commonEntityHints ?? []) as unknown[],
150	          defaultExcludedDocumentClasses:
151	            (payload.boundaryRules?.defaultExcludedDocumentClasses ??
152	              payload.suggestedRetrievalExclusions ??
153	              []) as string[],
154	          neighboringDomainIds: (payload.boundaryRules?.neighboringDomainIds ?? []) as string[],
155	          displayOrder: maxOrder + 10,
156	          isActive: true,
157	        })
158	        .onConflictDoNothing()
159	        .returning({ id: knowledgeTopDomains.id });
160	      afterState = { knowledgeTopDomainId: inserted?.id ?? id };
161	    } else {
162	      // merge_top_domains / split_top_domain / reassign_claims /
163	      // create_sub_topic / merge_sub_topics / split_sub_topic / retire_sub_topic
164	      // are intentionally NOT auto-applied. The proposal stays approved
165	      // (audit trail intact) but the reclassification work is left for
166	      // the dedicated reclassification job.
167	      queuedReclassification = true;
168	      afterState = {
169	        queuedFor: 'taxonomy-reclassification-worker',
170	        proposalType: proposal.proposalType,
171	        note: 'Mutation deferred — trigger task-id: taxonomy-reclassification.',
172	      };
173	    }
174	
175	    await tx.insert(taxonomyChangeLog).values({
176	      changeType: queuedReclassification
177	        ? `approve_pending_reclassification_${proposal.proposalType}`
178	        : `approve_${proposal.proposalType}`,
179	      beforeState: { proposalId, proposalType: proposal.proposalType, payload: proposal.payload },
180	      afterState,
181	      reason: reviewNote,
182	      approvedByEmployeeId: me.id,
183	      proposalId,
184	    });
185	  });
186	
187	  revalidatePath('/admin/taxonomy/proposals');
188	  revalidatePath('/admin/taxonomy');
189	  revalidatePath('/admin/taxonomy/change-log');
190	}
