192	// ─────────────────────────────────────────────────────────────────────────
193	// taxonomy_proposals — bulk approve / bulk reject
194	// ─────────────────────────────────────────────────────────────────────────
195	
196	export async function bulkApproveTaxonomyProposals(
197	  proposalIds: string[],
198	  reviewNote: string | null,
199	) {
200	  if (proposalIds.length === 0) return { approved: 0, errors: [] };
201	  const errors: Array<{ proposalId: string; error: string }> = [];
202	  let approved = 0;
203	  for (const id of proposalIds) {
204	    try {
205	      await approveTaxonomyProposal(id, reviewNote);
206	      approved++;
207	    } catch (e) {
208	      errors.push({ proposalId: id, error: e instanceof Error ? e.message : String(e) });
209	    }
210	  }
211	  return { approved, errors };
212	}
213	
214	export async function bulkRejectTaxonomyProposals(proposalIds: string[], reason: string) {
215	  if (!reason.trim()) throw new Error('A rejection reason is required for bulk reject.');
216	  if (proposalIds.length === 0) return { rejected: 0, errors: [] };
217	  const errors: Array<{ proposalId: string; error: string }> = [];
218	  let rejected = 0;
219	  for (const id of proposalIds) {
220	    try {
221	      await rejectTaxonomyProposal(id, reason);
222	      rejected++;
223	    } catch (e) {
224	      errors.push({ proposalId: id, error: e instanceof Error ? e.message : String(e) });
225	    }
226	  }
227	  return { rejected, errors };
228	}
