231	// entity_proposals — approve (creates entity) / reject / merge into existing
232	// ─────────────────────────────────────────────────────────────────────────
233	
234	export async function rejectEntityProposal(proposalId: string, reason: string) {
235	  const me = await requireAdmin();
236	  const db = getDirectDb();
237	
238	  await db.transaction(async (tx) => {
239	    const [proposal] = await tx
240	      .select()
241	      .from(entityProposals)
242	      .where(and(eq(entityProposals.id, proposalId), eq(entityProposals.status, 'pending')))
243	      .limit(1);
244	    if (!proposal) throw new Error('Entity proposal not found or already reviewed');
245	
246	    await tx
247	      .update(entityProposals)
248	      .set({
249	        status: 'rejected',
250	        reviewedByEmployeeId: me.id,
251	        reviewedAt: new Date(),
252	      })
253	      .where(eq(entityProposals.id, proposalId));
254	
255	    await tx.insert(taxonomyChangeLog).values({
256	      changeType: 'reject_entity_proposal',
257	      beforeState: {
258	        proposalId,
259	        proposedEntityType: proposal.proposedEntityType,
260	        proposedCanonicalValue: proposal.proposedCanonicalValue,
261	      },
262	      afterState: null,
263	      reason,
264	      approvedByEmployeeId: me.id,
265	    });
266	  });
267	
268	  revalidatePath('/admin/taxonomy/entity-proposals');
269	  revalidatePath('/admin/taxonomy/change-log');
270	}
271	
272	export async function approveEntityProposal(
273	  proposalId: string,
274	  // Allow the admin to refine the canonical value at approval time.
275	  finalCanonicalValue?: string,
276	  // Optional display label (defaults to canonical value).
277	  displayLabel?: string,
278	) {
279	  const me = await requireAdmin();
280	  const db = getDirectDb();
281	
282	  await db.transaction(async (tx) => {
283	    const [proposal] = await tx
284	      .select()
285	      .from(entityProposals)
286	      .where(and(eq(entityProposals.id, proposalId), eq(entityProposals.status, 'pending')))
287	      .limit(1);
288	    if (!proposal) throw new Error('Entity proposal not found or already reviewed');
289	
290	    const canonicalValue = (finalCanonicalValue ?? proposal.proposedCanonicalValue).trim();
291	    if (!canonicalValue) {
292	      throw new Error('canonical value must not be empty');
293	    }
294	
295	    const aliases = Array.isArray(proposal.rawStringsObserved)
296	      ? (proposal.rawStringsObserved as string[]).filter((s) => s && s !== canonicalValue)
297	      : [];
298	
299	    const [insertedEntity] = await tx
300	      .insert(entities)
301	      .values({
302	        entityType: proposal.proposedEntityType,
303	        canonicalValue,
304	        displayLabel: displayLabel ?? canonicalValue,
305	        aliases,
306	        domainHints: proposal.proposedDomainHints ?? [],
307	      })
308	      .onConflictDoNothing()
309	      .returning({ id: entities.id });
310	
311	    // If onConflictDoNothing returned no row, that means an entity with the
312	    // same (entity_type, canonical_value) already exists. Look it up so we
313	    // can merge against it instead of creating a duplicate.
314	    let entityId = insertedEntity?.id;
315	    if (!entityId) {
316	      const [existing] = await tx
317	        .select({ id: entities.id })
318	        .from(entities)
319	        .where(
320	          and(
321	            eq(entities.entityType, proposal.proposedEntityType),
322	            eq(entities.canonicalValue, canonicalValue),
323	          ),
324	        )
325	        .limit(1);
326	      if (!existing) throw new Error('failed to resolve entity after onConflictDoNothing');
327	      entityId = existing.id;
328	    }
329	
330	    await tx
331	      .update(entityProposals)
332	      .set({
333	        status: insertedEntity ? 'approved' : 'merged_into_existing',
334	        mergedIntoEntityId: entityId,
335	        reviewedByEmployeeId: me.id,
336	        reviewedAt: new Date(),
337	      })
338	      .where(eq(entityProposals.id, proposalId));
339	
340	    await tx.insert(taxonomyChangeLog).values({
341	      changeType: insertedEntity ? 'create_entity_from_proposal' : 'merge_entity_proposal',
342	      beforeState: {
343	        proposalId,
344	        proposedEntityType: proposal.proposedEntityType,
345	        proposedCanonicalValue: proposal.proposedCanonicalValue,
346	      },
347	      afterState: { entityId, finalCanonicalValue: canonicalValue },
348	      reason: null,
349	      approvedByEmployeeId: me.id,
350	    });
351	  });
352	
353	  revalidatePath('/admin/taxonomy/entity-proposals');
354	  revalidatePath('/admin/taxonomy/entities');
355	  revalidatePath('/admin/taxonomy/change-log');
356	}
