1	'use server';
2	
3	import { sql } from 'drizzle-orm';
4	import { revalidatePath } from 'next/cache';
5	import { requireAdmin } from '@/lib/auth-guard';
6	import { getDirectDb } from '@oracle/db/client';
7	import { triggerTask } from '@/lib/trigger';
8	
9	// Meeting picker actions.
10	//
11	// The Oracle does NOT auto-ingest meetings. `meeting_transcripts` holds the
12	// discovered meetings (status 'available'); an admin chooses which to ingest.
13	// Ingesting triggers teams-transcript-ingestion (which pulls the VTT, writes
14	// messages as 'pending' for normal extraction, and flips the row to 'ingested').
15	
16	function refresh() {
17	  revalidatePath('/admin/transcripts');
18	}
19	
20	/** Pull the discovery scan (past meetings) on demand. */
21	export async function runDiscoveryScan(formData: FormData) {
22	  await requireAdmin();
23	  const sinceDays = Number.parseInt(String(formData.get('sinceDays') ?? '14'), 10);
24	  await triggerTask('teams-transcript-discovery-scan', {
25	    sinceDays: Number.isFinite(sinceDays) ? sinceDays : 14,
26	  });
27	  refresh();
28	}
29	
30	/** Ingest the selected available meetings — the explicit "pull this in" action. */
31	export async function ingestMeetings(formData: FormData) {
32	  await requireAdmin();
33	  const ids = [
34	    ...new Set(formData.getAll('meetingId').map((v) => String(v).trim()).filter(Boolean)),
35	  ];
36	  if (ids.length === 0) return;
37	
38	  const db = getDirectDb();
39	  const result = await db.execute(sql`
40	    SELECT transcript_id, transcript_content_url, meeting_id, call_id, meeting_time
41	    FROM meeting_transcripts
42	    WHERE status = 'available'
43	      AND id IN (
44	        SELECT value::uuid FROM jsonb_array_elements_text(${JSON.stringify(ids)}::jsonb)
45	      )
46	  `);
47	  const rows = [...result] as unknown as Array<{
48	    transcript_id: string;
49	    transcript_content_url: string | null;
50	    meeting_id: string | null;
51	    call_id: string | null;
52	    meeting_time: string | null;
53	  }>;
54	
55	  for (const row of rows) {
56	    await triggerTask('teams-transcript-ingestion', {
57	      resourcePath: null,
58	      transcriptContentUrl: row.transcript_content_url,
59	      meetingId: row.meeting_id,
60	      callId: row.call_id,
61	      meetingTime: row.meeting_time,
62	      discoveryTranscriptId: row.transcript_id,
63	    });
64	  }
65	  refresh();
66	}
67	
68	/** Hide a meeting you don't want to ingest. */
69	export async function dismissMeeting(formData: FormData) {
70	  await requireAdmin();
71	  const id = String(formData.get('meetingId') ?? '').trim();
72	  if (!id) return;
73	  const db = getDirectDb();
74	  await db.execute(sql`
75	    UPDATE meeting_transcripts SET status = 'dismissed'
76	    WHERE id = ${id}::uuid AND status = 'available'
77	  `);
78	  refresh();
79	}
